function generateSeedAds(): Ad[] {
  const titles = [
    { t: "Cartofi de toamnă", cat: ["Legume"] },
    { t: "Coș cu bunătăți (Miere, Nuci, Fructe)", cat: ["Miere & Apicole", "Fructe", "Altele"] },
    { t: "Roșii de Grădină Bio", cat: ["Legume"] },
    { t: "Mobilă Pictată Manual", cat: ["Artizanat & Lucru Manual"] },
    { t: "Brânză de Burduf și Caș", cat: ["Lactate & Brânzeturi"] },
    { t: "Țuică de Prune și Sirop de Brad", cat: ["Băuturi & Siropuri", "Dulceață & Zacuști"] },
    { t: "Dulceață de Afine", cat: ["Dulceață & Zacuști"] },
    { t: "Mere Ionatan", cat: ["Fructe"] },
    { t: "Ouă de țară proaspete", cat: ["Ouuă"] },
    { t: "Cârnați de casă afumați", cat: ["Carne & Mezeluri"] }
  ];
  const counties = getCounties();

  return Array.from({ length: 24 }).map((_, i) => {
    const cIdx = Math.floor(Math.random() * counties.length);
    const county = counties[cIdx];
    const cities = getCities(county);
    const city = cities.length > 0 ? cities[Math.floor(Math.random() * cities.length)] : county;
    const villages = getVillages(county, city);
    const village = villages.length > 0 && Math.random() > 0.5 ? villages[Math.floor(Math.random() * villages.length)] : undefined;

    const template = titles[i % titles.length];

    // Select image based on primary category
    const primaryCat = template.cat[0];
    const catImages = CATEGORY_IMAGES[primaryCat] || CATEGORY_IMAGES["Altele"];
    const image = catImages[i % catImages.length];

    return {
      id: crypto.randomUUID(),
      title: template.t,
      description: "Vând produse proaspete, 100% naturale, din gospodăria proprie. Livrare personală în zonă sau prin curier. Calitate garantată!",
      price: Math.floor(Math.random() * 100) + 10,
      categories: template.cat,
      email: `producer${i}@demo.com`,
      phoneNumber: "0712345678",
      location: {
        county,
        city,
        village
      },
      images: [image],
      token: "demo-token",
      status: AdStatus.ACTIVE,
      createdAt: Date.now() - Math.floor(Math.random() * 1000000000),
      expiresAt: Date.now() + 1000000000,
    };
  });
}

import React, { useEffect, useState, useMemo } from 'react';
