export const createAd = async (payload: CreateAdPayload): Promise<{ adId: string; token: string; paymentUrl: string }> => {
  // RATE LIMITING CHECK
  const lastPost = localStorage.getItem(RATE_LIMIT_KEY);
  const now = Date.now();
  if (lastPost && now - parseInt(lastPost) < 120000) { // 2 minutes
    throw new Error("Rate limit exceeded. Please wait a moment before posting another ad.");
  }

  await delay(1000);

  const newId = crypto.randomUUID();
  const token = crypto.randomUUID().replace(/-/g, '') + crypto.randomUUID().replace(/-/g, '');

  let imageUrls: string[] = [];

  if (payload.images.length > 0) {
    try {
      const processed = await Promise.all(
        payload.images.slice(0, 3).map(file => processAndResizeImage(file))
      );
      imageUrls = processed;
    } catch (e) {
      console.error("Image processing failed", e);
      imageUrls = [`https://via.placeholder.com/400x300.png?text=Error`];
    }
  } else {
    imageUrls = [`https://via.placeholder.com/400x300.png?text=No+Image`];
  }

  const newAd: Ad = {
    id: newId,
    title: payload.title,
    description: payload.description,
    price: payload.price,
    categories: payload.categories, 
    email: payload.email,
    phoneNumber: payload.phoneNumber,
    location: payload.location,
    images: imageUrls,
    token: token,
    status: AdStatus.PENDING,
    createdAt: Date.now(),
    expiresAt: null,
    reviews: [],
    rating: 0
  };

  const ads = getAdsFromStorage();
  saveAdsToStorage([...ads, newAd]);

  // Set rate limit timestamp
  localStorage.setItem(RATE_LIMIT_KEY, now.toString());

  return {
    adId: newId,
    token: token,
    paymentUrl: `mock-stripe-checkout`, 
  };
};

export const simulatePaymentSuccess = async (adId: string): Promise<void> => {
  await delay(1500);
  const ads = getAdsFromStorage();
  const updatedAds = ads.map(ad => {
    if (ad.id === adId) {
      return {
        ...ad,
        status: AdStatus.ACTIVE,
        expiresAt: Date.now() + (28 * 24 * 60 * 60 * 1000) // 28 days as per plan
      };
    }
    return ad;
  });
  saveAdsToStorage(updatedAds);
};

export const verifyManageToken = async (id: string, token: string): Promise<Ad | null> => {
  await delay(500);
  const ads = getAdsFromStorage();
  const ad = ads.find(a => a.id === id);
  if (ad && ad.token === token) {
    return ad;
  }
  return null;
};

export const updateAd = async (id: string, token: string, updates: Partial<Ad>): Promise<boolean> => {
  await delay(800);
  const ads = getAdsFromStorage();
  const index = ads.findIndex(a => a.id === id && a.token === token);

  if (index === -1) return false;

  const updatedAd = { ...ads[index], ...updates };
  ads[index] = updatedAd;
  saveAdsToStorage(ads);
  return true;
};

export const deleteAd = async (id: string, token: string): Promise<boolean> => {
  await delay(500);
  const ads = getAdsFromStorage();
  const filtered = ads.filter(a => !(a.id === id && a.token === token));

  if (filtered.length === ads.length) return false;

  saveAdsToStorage(filtered);
  return true;
};

export const addReview = async (adId: string, review: Omit<Review, 'id' | 'createdAt'>): Promise<Review> => {
  await delay(500);
  const ads = getAdsFromStorage();
  const index = ads.findIndex(a => a.id === adId);

  if (index === -1) throw new Error("Ad not found");

  const newReview: Review = {
      ...review,
      id: crypto.randomUUID(),
      createdAt: Date.now()
  };

  const updatedReviews = [...(ads[index].reviews || []), newReview];

  // Recalculate rating
  const totalStars = updatedReviews.reduce((sum, r) => sum + r.rating, 0);
  const newRating = totalStars / updatedReviews.length;

  ads[index] = {
      ...ads[index],
      reviews: updatedReviews,
      rating: newRating
  };

  saveAdsToStorage(ads);
  return newReview;
};

// --- ADMIN API ---

export const getAllAds = async (): Promise<Ad[]> => {
  await delay(200);
  return getAdsFromStorage().sort((a, b) => b.createdAt - a.createdAt);
};

export const adminDeleteAd = async (id: string): Promise<boolean> => {
  await delay(300);
  const ads = getAdsFromStorage();
  const filtered = ads.filter(a => a.id !== id);

  if (filtered.length === ads.length) return false;

  saveAdsToStorage(filtered);
  return true;
};

export const resetDatabase = async (): Promise<void> => {
  await delay(1000);
  localStorage.removeItem(ADS_KEY);
  localStorage.removeItem('miculproducator_favorites');
  const seed = generateSeedAds();
  saveAdsToStorage(seed);
};

