};

import React, { useEffect, useState, useMemo } from 'react';
import { getAllAds, adminDeleteAd, resetDatabase } from '../services/mockBackend';
import { Ad, AdStatus, PRODUCT_CATEGORIES } from '../types';
import { Button } from '../components/Button';

interface AdminProps {
  onNavigate: (path: string) => void;
}

export const Admin: React.FC<AdminProps> = ({ onNavigate }) => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [pin, setPin] = useState('');

  // Data State
  const [ads, setAds] = useState<Ad[]>([]);
  const [loading, setLoading] = useState(false);

  // Tabs: 'dashboard' | 'moderation' | 'system'
  const [activeTab, setActiveTab] = useState<'dashboard' | 'moderation' | 'system'>('dashboard');

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (pin === '0000') { // Mock PIN
      setIsAuthenticated(true);
      fetchData();
    } else {
      alert('Invalid PIN');
    }
  };

  const fetchData = async () => {
    setLoading(true);
    try {
      const data = await getAllAds();
      setAds(data);
    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  };

  const handleDelete = async (id: string) => {
    if (!confirm("Are you sure you want to delete this ad? (Admin Override)")) return;
    try {
      await adminDeleteAd(id);
      fetchData(); // Refresh list
    } catch (e) {
      alert("Delete failed");
    }
  };

  const handleReset = async () => {
    if (!confirm("WARNING: This will wipe all current ads and restore seed data. Continue?")) return;
    setLoading(true);
    try {
      await resetDatabase();
      await fetchData();
      alert("Database reset successfully.");
    } catch (e) {
      alert("Reset failed");
    } finally {
      setLoading(false);
    }
  };

  const handleExport = () => {
      const dataStr = JSON.stringify(ads, null, 2);
      const dataUri = 'data:application/json;charset=utf-8,'+ encodeURIComponent(dataStr);

      const exportFileDefaultName = `miculproducator_backup_${new Date().toISOString().slice(0,10)}.json`;

      const linkElement = document.createElement('a');
      linkElement.setAttribute('href', dataUri);
      linkElement.setAttribute('download', exportFileDefaultName);
      linkElement.click();
  };

  const handleImport = (e: React.ChangeEvent<HTMLInputElement>) => {
      const fileReader = new FileReader();
      if (e.target.files && e.target.files.length > 0) {
          fileReader.readAsText(e.target.files[0], "UTF-8");
          fileReader.onload = (event) => {
              try {
                  const importedData = JSON.parse(event.target?.result as string);
                  if (Array.isArray(importedData)) {
                      if (confirm(`Found ${importedData.length} ads in backup. This will OVERWRITE current data. Proceed?`)) {
                          localStorage.setItem('miculproducator_ads_v8', JSON.stringify(importedData));
                          alert("Import successful! Refreshing data...");
                          fetchData();
                      }
                  } else {
                      alert("Invalid backup file format.");
                  }
              } catch (err) {
                  alert("Error parsing JSON file.");
              }
          };
      }
  };

  // Analytics Calculation
  const stats = useMemo(() => {
    const totalAds = ads.length;
    const totalActive = ads.filter(a => a.status === AdStatus.ACTIVE).length;
    const totalPending = ads.filter(a => a.status === AdStatus.PENDING).length;

    // Unique sellers (by email)
    const uniqueSellers = new Set(ads.map(a => a.email)).size;

    // Ads in last 24h
    const oneDayAgo = Date.now() - (24 * 60 * 60 * 1000);
    const newAds24h = ads.filter(a => a.createdAt > oneDayAgo).length;

    // Category Distribution
    const categoryCounts: Record<string, number> = {};
    ads.forEach(ad => {
        ad.categories.forEach(cat => {
            categoryCounts[cat] = (categoryCounts[cat] || 0) + 1;
        });
    });

    // Sort categories by count desc
    const topCategories = Object.entries(categoryCounts)
        .sort((a, b) => b[1] - a[1])
        .slice(0, 5); // Top 5

    return {
        totalAds,
        totalActive,
        totalPending,
        uniqueSellers,
        newAds24h,
        topCategories
    };
  }, [ads]);

  if (!isAuthenticated) {
    return (
      <div className="min-h-[60vh] flex items-center justify-center bg-gray-50 px-4">
        <div className="max-w-md w-full bg-white rounded-lg shadow-lg p-8">
          <div className="text-center mb-6">
            <h2 className="text-2xl font-bold text-gray-900">Admin Access</h2>
            <p className="text-sm text-gray-500 mt-2">Enter your security PIN to continue</p>
          </div>
          <form onSubmit={handleLogin} className="space-y-4">
            <div>
              <label className="block text-sm font-medium text-gray-700">PIN Code</label>
              <input 
                type="password" 
                value={pin}
                onChange={(e) => setPin(e.target.value)}
                placeholder="Hint: 0000"
                className="mt-1 block w-full border border-gray-300 rounded-md shadow-sm p-3 focus:ring-indigo-500 focus:border-indigo-500 text-center text-2xl tracking-widest"
                maxLength={4}
              />
            </div>
            <Button type="submit" className="w-full justify-center">Authenticate</Button>
          </form>
          <div className="mt-4 text-center">
             <button onClick={() => onNavigate('/')} className="text-sm text-gray-500 hover:text-gray-900 underline">
               Return to Home
             </button>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-100">
      {/* Admin Header */}
      <div className="bg-gray-900 text-white shadow">
         <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 h-16 flex items-center justify-between">
            <div className="flex items-center space-x-3">
               <span className="text-xl font-bold tracking-tight">MiculProducator Admin</span>
               <span className="bg-gray-700 px-2 py-0.5 rounded text-xs text-gray-300">v1.1.0</span>
            </div>
            <div className="flex items-center space-x-4">
               <button onClick={() => fetchData()} className="text-sm hover:text-indigo-300 flex items-center">
                  <svg className={`w-4 h-4 mr-1 ${loading ? 'animate-spin' : ''}`} fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" /></svg>
                  Refresh
               </button>
               <button onClick={() => setIsAuthenticated(false)} className="text-sm hover:text-red-300">Logout</button>
            </div>
         </div>
      </div>

      {/* Main Layout */}
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
         <div className="flex flex-col md:flex-row gap-6">

            {/* Sidebar Navigation */}
            <div className="w-full md:w-64 flex-shrink-0">
               <nav className="space-y-1">
                  <button
                    onClick={() => setActiveTab('dashboard')}
                    className={`w-full flex items-center px-4 py-3 text-sm font-medium rounded-md transition-colors ${
                       activeTab === 'dashboard' ? 'bg-indigo-600 text-white shadow-md' : 'bg-white text-gray-600 hover:bg-gray-50'
                    }`}
                  >
                    <svg className="mr-3 h-5 w-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6a2 2 0 012-2h2a2 2 0 012 2v2a2 2 0 01-2 2H6a2 2 0 01-2-2V6zM14 6a2 2 0 012-2h2a2 2 0 012 2v2a2 2 0 01-2 2h-2a2 2 0 01-2-2V6zM4 16a2 2 0 012-2h2a2 2 0 012 2v2a2 2 0 01-2 2H6a2 2 0 01-2-2v-2zM14 16a2 2 0 012-2h2a2 2 0 012 2v2a2 2 0 01-2 2h-2a2 2 0 01-2-2v-2z" /></svg>
                    Dashboard
                  </button>
                  <button
                    onClick={() => setActiveTab('moderation')}
                    className={`w-full flex items-center px-4 py-3 text-sm font-medium rounded-md transition-colors ${
