    // Generate random rating
    const rating = (Math.random() * 2) + 3; // 3 to 5 stars
    const reviewsCount = Math.floor(Math.random() * 5);
    const reviews: Review[] = Array.from({length: reviewsCount}).map((_, idx) => ({
        id: `seed-review-${i}-${idx}`,
        author: `User${Math.floor(Math.random() * 1000)}`,
        rating: Math.floor(Math.random() * 2) + 3,
        comment: "Produse foarte bune! Recomand cu incredere.",
        createdAt: Date.now() - Math.floor(Math.random() * 10000000)
    }));

    return {
      id: crypto.randomUUID(),
      title: template.t,
      description: "Vând produse proaspete, 100% naturale, din gospodăria proprie. Livrare personală în zonă sau prin curier. Calitate garantată!",
      price: Math.floor(Math.random() * 100) + 10,
      categories: template.cat,
      email: `producer${i}@demo.com`,
      phoneNumber: "0712345678",
      location: {
        county,
        city,
        village
      },
      images: [image],
      token: "demo-token",
      status: AdStatus.ACTIVE,
      createdAt: Date.now() - Math.floor(Math.random() * 1000000000),
      expiresAt: Date.now() + 1000000000,
      reviews: reviews,
      rating: reviews.length > 0 ? reviews.reduce((a, b) => a + b.rating, 0) / reviews.length : 0
    };
  });
}

import React, { useEffect, useState, useRef } from 'react';
import { Home } from './pages/Home';
import { CreateAd } from './pages/CreateAd';
import { AdDetails } from './pages/AdDetails';
import { ManageAd } from './pages/ManageAd';
import { Admin } from './pages/Admin';
import { Modal } from './components/Modal';
import { ToastContainer, ToastMessage, ToastType } from './components/Toast';
import { Ad, AppNotification } from './types';
import { fetchNotifications, markNotificationRead, clearAllNotifications, simulateIncomingAd } from './services/mockBackend';

const App: React.FC = () => {
  const [currentPath, setCurrentPath] = useState(window.location.hash || '#/');

  // Global States
  const [isCreateModalOpen, setIsCreateModalOpen] = useState(false);
  const [selectedAd, setSelectedAd] = useState<Ad | null>(null);

  // Toast State
  const [toasts, setToasts] = useState<ToastMessage[]>([]);

  // Favorites State
  const [favorites, setFavorites] = useState<string[]>([]);

  // Notifications State
  const [notifications, setNotifications] = useState<AppNotification[]>([]);
  const [showNotifDropdown, setShowNotifDropdown] = useState(false);
  const notifDropdownRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    // Load favorites from local storage on mount
    const saved = localStorage.getItem('miculproducator_favorites');
    if (saved) {
      setFavorites(JSON.parse(saved));
    }

    // Load initial notifications
    loadNotifications();

    // Listen for notification updates
    const handleNotifUpdate = () => loadNotifications();
    window.addEventListener('miculproducator:notifications_updated', handleNotifUpdate);

    // Setup click outside for dropdown
    const handleClickOutside = (event: MouseEvent) => {
        if (notifDropdownRef.current && !notifDropdownRef.current.contains(event.target as Node)) {
            setShowNotifDropdown(false);
        }
    };
    document.addEventListener('mousedown', handleClickOutside);

    return () => {
        window.removeEventListener('miculproducator:notifications_updated', handleNotifUpdate);
        document.removeEventListener('mousedown', handleClickOutside);
    };
  }, []);

  const loadNotifications = async () => {
      const data = await fetchNotifications();
      setNotifications(data);
  };

  const addToast = (type: ToastType, message: string) => {
    const id = Math.random().toString(36).substr(2, 9);
    setToasts((prev) => [...prev, { id, type, message }]);
  };

  const removeToast = (id: string) => {
    setToasts((prev) => prev.filter((t) => t.id !== id));
  };

  const handleToggleFavorite = (id: string) => {
    let newFavs: string[];
    if (favorites.includes(id)) {
      newFavs = favorites.filter(fav => fav !== id);
      addToast('info', 'Removed from favorites');
    } else {
      newFavs = [...favorites, id];
      addToast('success', 'Added to favorites');
    }
    setFavorites(newFavs);
    localStorage.setItem('miculproducator_favorites', JSON.stringify(newFavs));
  };

  const handleNotifClick = async (notif: AppNotification) => {
      await markNotificationRead(notif.id);
      loadNotifications();
      if (notif.adId) {
          navigate(`/ad/${notif.adId}`);
          setShowNotifDropdown(false);
      }
  };

  const handleClearNotifs = async () => {
      await clearAllNotifications();
      loadNotifications();
  };

  const handleSimulateAd = () => {
      simulateIncomingAd();
      addToast('info', 'Simulating: A new ad was just posted by another user...');
  };

  useEffect(() => {
    const handleHashChange = () => {
      setCurrentPath(window.location.hash || '#/');
    };

    window.addEventListener('hashchange', handleHashChange);
    return () => window.removeEventListener('hashchange', handleHashChange);
  }, []);

  const navigate = (path: string) => {
    window.location.hash = path;
  };

  const handleOpenAdDetails = (ad: Ad) => {
    setSelectedAd(ad);
  };

  const handleCloseAdDetails = () => {
    setSelectedAd(null);
  };

  // Route matching logic
  const renderRoute = () => {
    const path = currentPath.replace('#', '');
    const searchParams = new URLSearchParams(path.split('?')[1]);
    const cleanPath = path.split('?')[0];

    if (cleanPath === '/' || cleanPath === '') {
      return (
        <Home 
          onNavigate={navigate} 
          onOpenCreateModal={() => setIsCreateModalOpen(true)}
          onAdClick={handleOpenAdDetails}
          favoriteIds={favorites}
          onToggleFavorite={handleToggleFavorite}
          onAddToast={addToast}
        />
      );
    }

    if (cleanPath === '/create') {
      return <CreateAd onNavigate={navigate} />;
    }

    if (cleanPath === '/admin') {
      return <Admin onNavigate={navigate} />;
    }

    if (cleanPath.startsWith('/ad/')) {
      const id = cleanPath.split('/ad/')[1];
      return (
        <AdDetails 
          id={id} 
          onNavigate={navigate} 
          isFavorite={favorites.includes(id)}
          onToggleFavorite={() => handleToggleFavorite(id)}
          onAddToast={addToast}
        />
      );
    }

    if (cleanPath === '/manage') {
      const id = searchParams.get('id');
      const token = searchParams.get('token');
      if (id && token) {
        return <ManageAd id={id} token={token} onNavigate={navigate} />;
      }
      return <div className="p-8 text-center text-red-600">Missing management credentials. Check your link.</div>;
    }

    return <div className="p-8 text-center">404 - Page Not Found</div>;
  };

  const unreadCount = notifications.filter(n => !n.isRead).length;

  return (
    <div className="min-h-screen flex flex-col font-sans">
      {/* Skip Navigation Link for Accessibility */}
      <a href="#main-content" className="sr-only focus:not-sr-only focus:absolute focus:top-4 focus:left-4 bg-indigo-600 text-white p-3 rounded shadow-lg z-50">
        Skip to content
      </a>

      <header className="bg-white/95 backdrop-blur-md shadow-sm sticky top-0 z-30 transition-all border-b border-gray-100">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between h-16 items-center">
            <div className="flex cursor-pointer group" onClick={() => navigate('/')} role="button" tabIndex={0} onKeyDown={(e) => e.key === 'Enter' && navigate('/')}>
              <div className="flex-shrink-0 flex items-center">
                <span className="text-2xl font-black text-indigo-600 tracking-tight group-hover:scale-105 transition-transform duration-200">
                   MiculProducator
                </span>
              </div>
            </div>

            <div className="flex items-center space-x-2 sm:space-x-4">
              {/* Notification Bell */}
              <div className="relative" ref={notifDropdownRef}>
                  <button 
                    onClick={() => setShowNotifDropdown(!showNotifDropdown)}
                    className="p-2 rounded-full text-gray-500 hover:bg-gray-100 hover:text-indigo-600 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-indigo-500 relative transition-colors"
                    aria-label="Notifications"
                  >
                      <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 17h5l-1.405-1.405A2.032 2.032 0 0118 14.158V11a6.002 6.002 0 00-4-5.659V5a2 2 0 10-4 0v.341C7.67 6.165 6 8.388 6 11v3.159c0 .538-.214 1.055-.595 1.436L4 17h5m6 0v1a3 3 0 11-6 0v-1m6 0H9" /></svg>
                      {unreadCount > 0 && (
                          <span className="absolute top-1.5 right-1.5 block h-2.5 w-2.5 rounded-full bg-red-500 ring-2 ring-white animate-pulse"></span>
                      )}
                  </button>

                  {/* Dropdown */}
                  {showNotifDropdown && (
                      <div className="absolute right-0 mt-2 w-80 bg-white rounded-md shadow-lg overflow-hidden z-50 border border-gray-100 animate-fade-in origin-top-right">
                          <div className="py-2 px-4 bg-gray-50 border-b border-gray-100 flex justify-between items-center">
                              <h3 className="text-sm font-bold text-gray-700">Notifications</h3>
                              {notifications.length > 0 && (
                                  <button onClick={handleClearNotifs} className="text-xs text-indigo-600 hover:text-indigo-800">Clear All</button>
                              )}
                          </div>
                          <div className="max-h-96 overflow-y-auto">
                              {notifications.length === 0 ? (
                                  <div className="p-4 text-center text-sm text-gray-500">No new notifications.</div>
                              ) : (
                                  notifications.map(notif => (
                                      <div 
                                        key={notif.id} 
                                        onClick={() => handleNotifClick(notif)}
                                        className={`px-4 py-3 border-b border-gray-100 cursor-pointer hover:bg-gray-50 transition-colors ${!notif.isRead ? 'bg-indigo-50/50' : ''}`}
                                      >
                                          <p className="text-sm font-semibold text-gray-800">{notif.title}</p>
                                          <p className="text-xs text-gray-600 mt-1 line-clamp-2">{notif.message}</p>
                                          <p className="text-[10px] text-gray-400 mt-1 text-right">{new Date(notif.timestamp).toLocaleTimeString()}</p>
                                      </div>
                                  ))
                              )}
                          </div>
                      </div>
                  )}
              </div>

              <button
                onClick={() => setIsCreateModalOpen(true)}
                className="ml-2 px-4 py-2 border border-transparent text-sm font-semibold rounded-full shadow-md text-white bg-indigo-600 hover:bg-indigo-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-indigo-500 transition-all duration-300 transform hover:-translate-y-0.5 hidden sm:inline-flex"
              >
                + Post Ad
              </button>
              {/* Mobile compact button */}
              <button
                onClick={() => setIsCreateModalOpen(true)}
                className="ml-2 p-2 rounded-full bg-indigo-600 text-white shadow-md sm:hidden hover:bg-indigo-700"
                aria-label="Create Ad"
              >
                  <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" /></svg>
              </button>
            </div>
          </div>
        </div>
      </header>

      <main id="main-content" className="flex-grow bg-gray-50 focus:outline-none" tabIndex={-1}>
        {renderRoute()}
      </main>

      <footer className="bg-white border-t border-gray-200">
        <div className="max-w-7xl mx-auto py-8 px-4 sm:px-6 lg:px-8">
          <div className="flex flex-col md:flex-row justify-between items-center gap-4">
             <div className="mb-4 md:mb-0">
               <span className="text-xl font-bold text-gray-300">MiculProducator</span>
             </div>
             <div className="flex flex-wrap justify-center gap-4 text-sm text-gray-500">
                <button onClick={handleSimulateAd} className="text-indigo-400 hover:text-indigo-600 underline">
                    Demo: Simulate Incoming Ad
                </button>
                <span>&copy; {new Date().getFullYear()} Made with ❤️ for Romania.</span>
                <button 
                  onClick={() => navigate('/admin')} 
                  className="text-gray-300 hover:text-gray-500 transition-colors focus:outline-none focus:underline"
                >
                  Admin Panel
                </button>
             </div>
          </div>
        </div>
      </footer>

      <Modal 
        isOpen={isCreateModalOpen} 
        onClose={() => setIsCreateModalOpen(false)}
        title="Create New Listing"
      >
        <CreateAd 
          onNavigate={navigate} 
          onClose={() => setIsCreateModalOpen(false)}
        />
      </Modal>

      <Modal
        isOpen={!!selectedAd}
        onClose={handleCloseAdDetails}
        title="Listing Details"
      >
        {selectedAd && (
          <AdDetails 
            id={selectedAd.id}
            initialData={selectedAd} 
            onClose={handleCloseAdDetails}
            isFavorite={favorites.includes(selectedAd.id)}
            onToggleFavorite={() => handleToggleFavorite(selectedAd.id)}
            onAddToast={addToast}
          />
        )}
      </Modal>

      <ToastContainer toasts={toasts} removeToast={removeToast} />
    </div>
  );
};

export default App;

import React, { useEffect, useState, useMemo } from 'react';
import { AdCard } from '../components/AdCard';
import { Carousel, Slide } from '../components/Carousel';
import { CategoryNav } from '../components/CategoryNav';
import { fetchActiveAds, subscribeToAlert } from '../services/mockBackend';
import { Ad, ToastType } from '../types';
import { getCounties, getCities, getVillages } from '../data/locations';
import { getCountiesOnRoute } from '../utils/routeGraph';

interface HomeProps {
  onNavigate: (path: string) => void;
  onOpenCreateModal: () => void;
  onAdClick: (ad: Ad) => void;
  favoriteIds: string[];
  onToggleFavorite: (id: string) => void;
  onAddToast?: (type: ToastType, msg: string) => void;
}

export const Home: React.FC<HomeProps> = ({ 
  onNavigate, 
  onOpenCreateModal, 
  onAdClick,
  favoriteIds,
  onToggleFavorite,
  onAddToast
}) => {
  const [ads, setAds] = useState<Ad[]>([]);
  const [loading, setLoading] = useState(true);

  // Pagination State
  const [currentPage, setCurrentPage] = useState(1);
  const itemsPerPage = 12;

  // Search Mode: 'local' (Standard) or 'route' (Travel)
  const [searchMode, setSearchMode] = useState<'local' | 'route'>('local');

  // Filters
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedCategory, setSelectedCategory] = useState('');
  const [showFavoritesOnly, setShowFavoritesOnly] = useState(false);

  // Local Mode State
  const [filterCounty, setFilterCounty] = useState('');
  const [filterCity, setFilterCity] = useState('');
  const [filterVillage, setFilterVillage] = useState('');
  const [availableCities, setAvailableCities] = useState<string[]>([]);
  const [availableVillages, setAvailableVillages] = useState<string[]>([]);

  // Route Mode State
  const [routeStartCounty, setRouteStartCounty] = useState('');
  const [routeStartCity, setRouteStartCity] = useState(''); 
  const [routeEndCounty, setRouteEndCounty] = useState('');
  const [routeEndCity, setRouteEndCity] = useState('');
  const [calculatedRouteCounties, setCalculatedRouteCounties] = useState<string[]>([]);

  // Route Dropdown Options
  const [startCities, setStartCities] = useState<string[]>([]);
  const [endCities, setEndCities] = useState<string[]>([]);

  const loadAds = async () => {
    try {
      const data = await fetchActiveAds();
      setAds(data);
    } catch (err) {
      console.error("Failed to load ads", err);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadAds();

    // Listen for updates from other components (e.g. AdDetails Review submission)
    const handleAdUpdate = (event: Event) => {
        // We could optimize by only updating the specific ID, but for this app size, refetching is cleaner
        // and ensures sorting (e.g. if we add sort by rating) remains correct.
        loadAds();
    };

    window.addEventListener('miculproducator:ad_updated', handleAdUpdate);
    return () => window.removeEventListener('miculproducator:ad_updated', handleAdUpdate);
  }, []);

  // Reset to Page 1 when any filter changes
  useEffect(() => {
    setCurrentPage(1);
  }, [
    searchTerm, 
    selectedCategory, 
    showFavoritesOnly, 
    filterCounty, 
    filterCity, 
    filterVillage, 
    routeStartCounty, 
    routeEndCounty,
    searchMode
  ]);

  // Cascading Filters (Local Mode)
  useEffect(() => {
    if (filterCounty) {
      setAvailableCities(getCities(filterCounty));
      setFilterCity('');
      setFilterVillage('');
      setAvailableVillages([]);
    } else {
      setAvailableCities([]);
      setFilterCity('');
      setFilterVillage('');
      setAvailableVillages([]);
    }
  }, [filterCounty]);

  useEffect(() => {
    if (filterCounty && filterCity) {
      setAvailableVillages(getVillages(filterCounty, filterCity));
      setFilterVillage('');
    } else {
      setAvailableVillages([]);
      setFilterVillage('');
    }
  }, [filterCounty, filterCity]);

  // Route Mode Cascading
  useEffect(() => {
    if (routeStartCounty) {
      setStartCities(getCities(routeStartCounty));
      setRouteStartCity('');
    } else {
      setStartCities([]);
    }
  }, [routeStartCounty]);

  useEffect(() => {
    if (routeEndCounty) {
      setEndCities(getCities(routeEndCounty));
      setRouteEndCity('');
    } else {
      setEndCities([]);
    }
  }, [routeEndCounty]);

  // Route Calculation
  useEffect(() => {
    if (searchMode === 'route' && routeStartCounty && routeEndCounty) {
      const path = getCountiesOnRoute(routeStartCounty, routeEndCounty);
      setCalculatedRouteCounties(path);
    } else {
      setCalculatedRouteCounties([]);
    }
  }, [searchMode, routeStartCounty, routeEndCounty]);

  // --- Filtering & Sorting Logic (Memoized) ---
  const processedAds = useMemo(() => {
    // 1. Filter
    const filtered = ads.filter(ad => {
      // Keyword
      const matchesSearch = 
        ad.title.toLowerCase().includes(searchTerm.toLowerCase()) || 
        ad.description.toLowerCase().includes(searchTerm.toLowerCase());

      // Category: Match if selected category is ONE OF the ad's categories
      const matchesCategory = selectedCategory ? ad.categories.includes(selectedCategory) : true;

      // Location
      const adLocation = ad.location || { county: '', city: '', village: '' };
      let matchesLocation = true;

      if (searchMode === 'local') {
        const matchesCounty = filterCounty ? adLocation.county === filterCounty : true;
        const matchesCity = filterCity ? adLocation.city === filterCity : true;
        const matchesVillage = filterVillage ? adLocation.village === filterVillage : true;
        matchesLocation = matchesCounty && matchesCity && matchesVillage;
      } else {
        // Route Mode: Include ALL ads in the calculated counties
        if (routeStartCounty && routeEndCounty && calculatedRouteCounties.length > 0) {
          matchesLocation = calculatedRouteCounties.includes(adLocation.county);
        }
      }

      // Favorites
      const matchesFavorite = showFavoritesOnly ? favoriteIds.includes(ad.id) : true;

      return matchesSearch && matchesCategory && matchesLocation && matchesFavorite;
    });

    // 2. Sort
    return filtered.sort((a, b) => {
      // Priority: Route Order (if in route mode)
      if (searchMode === 'route' && calculatedRouteCounties.length > 0) {
        const idxA = calculatedRouteCounties.indexOf(a.location.county);
        const idxB = calculatedRouteCounties.indexOf(b.location.county);

        // If counties are different, sort by position in route (Start -> End)
        if (idxA !== -1 && idxB !== -1 && idxA !== idxB) {
          return idxA - idxB;
        }
      }

      // Secondary: Date (Newest first)
      return b.createdAt - a.createdAt;
    });
  }, [
    ads, 
    searchTerm, 
    selectedCategory, 
    searchMode, 
    filterCounty, 
    filterCity, 
    filterVillage, 
    routeStartCounty, 
    routeEndCounty, 
    calculatedRouteCounties, 
    showFavoritesOnly, 
    favoriteIds
  ]);

  // --- Pagination Logic ---
  const totalPages = Math.ceil(processedAds.length / itemsPerPage);
  const currentAds = processedAds.slice(
    (currentPage - 1) * itemsPerPage,
    currentPage * itemsPerPage
  );

  const handlePageChange = (page: number) => {
    setCurrentPage(page);
    document.getElementById('listings')?.scrollIntoView({ behavior: 'smooth' });
  };

  const handleSubscribeCategory = async () => {
      if (!selectedCategory) return;
      await subscribeToAlert({ category: selectedCategory }, 'category');
      if (onAddToast) onAddToast('success', `Alert set for new "${selectedCategory}" items!`);
  };

  const handleSubscribeLocation = async () => {
      if (!filterCounty) return;
      await subscribeToAlert({ county: filterCounty }, 'search');
      if (onAddToast) onAddToast('success', `Alert set for ads in "${filterCounty}"!`);
  };

  const heroSlides: Slide[] = [
    {
      id: '1',
      image: 'https://images.unsplash.com/photo-1488459716781-31db52582fe9?auto=format&fit=crop&q=80&w=2000',
      title: 'Support Local Producers',
      description: 'Discover fresh, handmade, and unique products directly from the source. Join MiculProducator today.',
      ctaText: 'Start Selling Now',
      onCtaClick: onOpenCreateModal,
    },
    {
      id: '2',
      image: 'https://images.unsplash.com/photo-1615485925763-867862780c10?auto=format&fit=crop&q=80&w=2000',
      title: 'Fresh from the Garden',
      description: 'Find seasonal vegetables, organic fruits, and artisanal foods right in your neighborhood.',
      ctaText: 'Browse Fresh Food',
      onCtaClick: () => {
        setSelectedCategory('Legume');
        document.getElementById('listings')?.scrollIntoView({ behavior: 'smooth' });
      },
    },
    {
      id: '3',
      image: 'https://images.unsplash.com/photo-1469854523086-cc02fe5d8800?auto=format&fit=crop&q=80&w=2000',
      title: 'Traveling across Romania?',
      description: 'Find fresh food and products along your route. Support locals wherever you go.',
      ctaText: 'Plan Route',
      onCtaClick: () => {
        setSearchMode('route');
        document.getElementById('listings')?.scrollIntoView({ behavior: 'smooth' });
      },
    }
  ];

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">

      {/* Header Carousel */}
      <Carousel slides={heroSlides} />

      {/* Visual Category Navigation */}
      <div className="relative">
          <CategoryNav selectedCategory={selectedCategory} onSelectCategory={setSelectedCategory} />
          {selectedCategory && (
              <div className="flex justify-end -mt-6 mb-6">
                  <button 
                    onClick={handleSubscribeCategory}
                    className="flex items-center text-xs font-semibold text-indigo-600 hover:text-indigo-800 bg-indigo-50 px-3 py-1.5 rounded-full transition-colors"
                  >
                      <svg className="w-4 h-4 mr-1" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 17h5l-1.405-1.405A2.032 2.032 0 0118 14.158V11a6.002 6.002 0 00-4-5.659V5a2 2 0 10-4 0v.341C7.67 6.165 6 8.388 6 11v3.159c0 .538-.214 1.055-.595 1.436L4 17h5m6 0v1a3 3 0 11-6 0v-1m6 0H9" /></svg>
                      Notify me about new {selectedCategory}
                  </button>
              </div>
          )}
      </div>

      <div id="listings" className="mb-6">
        <div className="flex flex-col sm:flex-row justify-between items-end mb-6 gap-4">
           <div>
             <h1 className="text-3xl font-bold text-gray-900">Latest Listings</h1>
             <p className="text-gray-500 mt-1">Discover great deals or sell your items today.</p>
           </div>

           <div className="flex space-x-2">
            <button
               onClick={() => setShowFavoritesOnly(!showFavoritesOnly)}
               className={`flex items-center px-4 py-2 rounded-full border text-sm font-medium transition-colors ${
                  showFavoritesOnly 
                    ? 'bg-red-50 text-red-600 border-red-200' 
                    : 'bg-white text-gray-600 border-gray-300 hover:bg-gray-50'
               }`}
             >
               <svg className={`w-4 h-4 mr-2 ${showFavoritesOnly ? 'fill-current' : ''}`} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4.318 6.318a4.5 4.5 0 000 6.364L12 20.364l7.682-7.682a4.5 4.5 0 00-6.364-6.364L12 7.636l-1.318-1.318a4.5 4.5 0 00-6.364 0z" /></svg>
               {showFavoritesOnly ? 'Show All' : 'Show Favorites'}
             </button>
           </div>
        </div>

        {/* Search & Filter Bar */}
        <div className="bg-white rounded-xl border border-gray-200 shadow-sm overflow-hidden">
           {/* Mode Toggles */}
           <div className="flex border-b border-gray-100">
             <button
                onClick={() => setSearchMode('local')}
                className={`flex-1 py-3 text-sm font-medium text-center transition-colors flex items-center justify-center ${
                  searchMode === 'local' ? 'bg-indigo-50 text-indigo-700 border-b-2 border-indigo-600' : 'text-gray-500 hover:bg-gray-50'
                }`}
             >
               <svg className="w-5 h-5 mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 12l2-2m0 0l7-7 7 7M5 10v10a1 1 0 001 1h3m10-11l2 2m-2-2v10a1 1 0 01-1 1h-3m-6 0a1 1 0 001-1v-4a1 1 0 011-1h2a1 1 0 011 1v4a1 1 0 001 1m-6 0h6" /></svg>
               Find Locally
             </button>
             <button
                onClick={() => setSearchMode('route')}
                className={`flex-1 py-3 text-sm font-medium text-center transition-colors flex items-center justify-center ${
                  searchMode === 'route' ? 'bg-indigo-50 text-indigo-700 border-b-2 border-indigo-600' : 'text-gray-500 hover:bg-gray-50'
                }`}
             >
               <svg className="w-5 h-5 mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 7h8m0 0v8m0-8l-8 8-4-4-6 6" /></svg>
               On the Road (Travel Mode)
             </button>
           </div>

           <div className="p-4 animate-fade-in">
             {/* Common: Keyword Search */}
             <div className="mb-4">
               <label className="block text-xs font-bold text-gray-700 uppercase tracking-wide mb-1">Search Products</label>
               <input
                 type="text"
                 placeholder="e.g. Tomatoes, Honey..."
                 value={searchTerm}
                 onChange={(e) => setSearchTerm(e.target.value)}
                 className="w-full rounded-lg border-gray-300 border p-2.5 focus:ring-indigo-500 focus:border-indigo-500"
               />
             </div>

             {searchMode === 'local' ? (
               <div className="grid grid-cols-1 md:grid-cols-3 gap-4 relative">
                {/* Local Filters */}
                 <div>
                   <label className="block text-xs font-bold text-gray-700 uppercase tracking-wide mb-1">Județ</label>
                   <select
                     value={filterCounty}
                     onChange={(e) => setFilterCounty(e.target.value)}
                     className="w-full rounded-lg border-gray-300 border p-2.5 bg-white focus:ring-indigo-500 focus:border-indigo-500"
                   >
                     <option value="">Toate Județele</option>
                     {getCounties().map(c => (
                       <option key={c} value={c}>{c}</option>
                     ))}
                   </select>
                 </div>
                 <div>
                   <label className="block text-xs font-bold text-gray-700 uppercase tracking-wide mb-1">Oraș (City)</label>
                    <select
                     value={filterCity}
                     onChange={(e) => setFilterCity(e.target.value)}
                     disabled={!filterCounty}
                     className="w-full rounded-lg border-gray-300 border p-2.5 bg-white focus:ring-indigo-500 focus:border-indigo-500 disabled:bg-gray-100 disabled:text-gray-400"
                   >
                     <option value="">Toate Orașele</option>
                     {availableCities.map(c => (
                       <option key={c} value={c}>{c}</option>
                     ))}
                   </select>
                 </div>
                 <div className="relative">
                   <label className="block text-xs font-bold text-gray-700 uppercase tracking-wide mb-1">Sat (Village)</label>
                    <select
                     value={filterVillage}
                     onChange={(e) => setFilterVillage(e.target.value)}
                     disabled={!filterCity || availableVillages.length === 0}
                     className="w-full rounded-lg border-gray-300 border p-2.5 bg-white focus:ring-indigo-500 focus:border-indigo-500 disabled:bg-gray-100 disabled:text-gray-400"
                   >
                     <option value="">Toate Satele</option>
                     {availableVillages.map(v => (
                       <option key={v} value={v}>{v}</option>
                     ))}
                   </select>

                   {/* Notify for Location Button */}
                   {filterCounty && (
                       <button 
                         onClick={handleSubscribeLocation}
                         className="absolute right-0 -bottom-6 text-[10px] font-bold text-indigo-600 hover:text-indigo-800 flex items-center"
                       >
                           <svg className="w-3 h-3 mr-1" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 17h5l-1.405-1.405A2.032 2.032 0 0118 14.158V11a6.002 6.002 0 00-4-5.659V5a2 2 0 10-4 0v.341C7.67 6.165 6 8.388 6 11v3.159c0 .538-.214 1.055-.595 1.436L4 17h5m6 0v1a3 3 0 11-6 0v-1m6 0H9" /></svg>
                           Alerts for {filterCounty}
                       </button>
                   )}
                 </div>
               </div>
             ) : (
               <div className="space-y-4">
                 <div className="grid grid-cols-1 md:grid-cols-2 gap-4 items-center">
                    {/* Start Point */}
                    <div className="bg-gray-50 p-3 rounded-lg border border-gray-100">
                         <label className="block text-xs font-bold text-gray-700 uppercase tracking-wide mb-2 flex items-center">
                           <span className="w-2 h-2 rounded-full bg-green-500 mr-2"></span>
                           Pornire (Start Point)
                         </label>
                         <div className="grid grid-cols-2 gap-2">
                             <select
                               value={routeStartCounty}
                               onChange={(e) => setRouteStartCounty(e.target.value)}
                               className="w-full rounded-lg border-gray-300 border p-2 text-sm focus:ring-indigo-500"
                             >
                               <option value="">Select Județ</option>
                               {getCounties().map(c => (
                                 <option key={c} value={c}>{c}</option>
                               ))}
                             </select>
                             <select
                               value={routeStartCity}
                               onChange={(e) => setRouteStartCity(e.target.value)}
                               disabled={!routeStartCounty}
                               className="w-full rounded-lg border-gray-300 border p-2 text-sm focus:ring-indigo-500 disabled:bg-gray-100"
                             >
                               <option value="">Select Oraș (Opt)</option>
                               {startCities.map(c => (
                                 <option key={c} value={c}>{c}</option>
                               ))}
                             </select>
                         </div>
                    </div>

                    {/* End Point */}
                    <div className="bg-gray-50 p-3 rounded-lg border border-gray-100">
                         <label className="block text-xs font-bold text-gray-700 uppercase tracking-wide mb-2 flex items-center">
                           <span className="w-2 h-2 rounded-full bg-red-500 mr-2"></span>
                           Destinație (End Point)
                         </label>
                         <div className="grid grid-cols-2 gap-2">
                             <select
                               value={routeEndCounty}
                               onChange={(e) => setRouteEndCounty(e.target.value)}
                               className="w-full rounded-lg border-gray-300 border p-2 text-sm focus:ring-indigo-500"
                             >
                               <option value="">Select Județ</option>
                               {getCounties().map(c => (
                                 <option key={c} value={c}>{c}</option>
                               ))}
                             </select>
                             <select
                               value={routeEndCity}
                               onChange={(e) => setRouteEndCity(e.target.value)}
                               disabled={!routeEndCounty}
                               className="w-full rounded-lg border-gray-300 border p-2 text-sm focus:ring-indigo-500 disabled:bg-gray-100"
                             >
                               <option value="">Select Oraș (Opt)</option>
                               {endCities.map(c => (
                                 <option key={c} value={c}>{c}</option>
                               ))}
                             </select>
                         </div>
                    </div>
                 </div>

                 {calculatedRouteCounties.length > 0 ? (
                    <div className="bg-indigo-50 border border-indigo-100 rounded-lg p-4">
                      <div className="flex flex-col">
                        <div className="flex items-center justify-between mb-3">
                            <span className="text-sm font-bold text-indigo-900 uppercase tracking-wider">Your Journey</span>
                            <span className="text-xs bg-indigo-200 text-indigo-800 px-2 py-0.5 rounded-full">{calculatedRouteCounties.length} Stops</span>
                        </div>

                        {/* Visual Route Stepper */}
                        <div className="relative flex items-center overflow-x-auto pb-2 scrollbar-hide space-x-6">
                            {/* Connecting Line - Background */}
                            <div className="absolute top-1/2 left-4 right-4 h-0.5 bg-indigo-200 -z-10 transform -translate-y-1/2" style={{ width: `${(calculatedRouteCounties.length - 1) * 80}px` }}></div>

                            {calculatedRouteCounties.map((county, idx) => (
                                <div key={county} className="flex flex-col items-center flex-shrink-0 group relative z-10">
                                    <div className={`w-8 h-8 rounded-full flex items-center justify-center text-xs font-bold border-2 transition-all ${
                                        idx === 0 ? 'bg-green-500 border-green-600 text-white' :
                                        idx === calculatedRouteCounties.length - 1 ? 'bg-red-500 border-red-600 text-white' :
                                        'bg-white border-indigo-400 text-indigo-700 group-hover:bg-indigo-50'
                                    }`}>
                                        {idx + 1}
                                    </div>
                                    <span className="mt-2 text-xs font-medium text-gray-700 bg-white/80 px-1 rounded truncate max-w-[80px]">
                                        {county}
                                    </span>
                                </div>
                            ))}
                        </div>

                        <p className="text-xs text-indigo-600 mt-2 border-t border-indigo-100 pt-2">
                           Showing listings from all cities and <span className="underline font-bold">surrounding villages (sate)</span> along this route.
                        </p>
                      </div>
                    </div>
                 ) : (
                    <div className="text-center text-xs text-gray-400 py-2">
                      Select a Start and End County/City to find listings along your path.
                    </div>
                 )}
               </div>
             )}
           </div>
        </div>
      </div>

      {loading ? (
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
          {[...Array(8)].map((_, i) => (
            <div key={i} className="animate-pulse bg-white h-80 rounded-xl border border-gray-200"></div>
          ))}
        </div>
      ) : processedAds.length === 0 ? (
        <div className="text-center py-24 bg-white rounded-xl border border-gray-200">
          <div className="mx-auto h-24 w-24 bg-gray-100 rounded-full flex items-center justify-center mb-4">
             <svg className="h-10 w-10 text-gray-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
               <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11H5m14 0a2 2 0 012 2v6a2 2 0 01-2 2H5a2 2 0 01-2-2v-6a2 2 0 012-2m14 0V9a2 2 0 00-2-2M5 11V9a2 2 0 012-2m0 0V5a2 2 0 012-2h6a2 2 0 012 2v2M7 7h10" />
             </svg>
          </div>
          <h3 className="mt-2 text-lg font-medium text-gray-900">No active ads found</h3>
          <p className="mt-1 text-gray-500">
             {searchMode === 'route' ? 'No ads found in the counties along this route.' : 'Try adjusting your filters or create a new listing.'}
          </p>
          <div className="mt-6">
            <button
              onClick={onOpenCreateModal}
              className="inline-flex items-center px-6 py-3 border border-transparent text-base font-medium rounded-md text-white bg-indigo-600 hover:bg-indigo-700 shadow-md"
            >
              Post an Ad
            </button>
          </div>
        </div>
      ) : (
        <>
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
            {currentAds.map((ad, index) => (
              <AdCard 
                key={ad.id} 
                ad={ad} 
                onClick={() => onAdClick(ad)} 
                isFavorite={favoriteIds.includes(ad.id)}
                onToggleFavorite={(e) => {
                  e.stopPropagation();
                  onToggleFavorite(ad.id);
                }}
                priority={index < 6}
              />
            ))}
          </div>

          {/* Pagination Controls */}
          {totalPages > 1 && (
            <div className="mt-12 flex justify-center items-center space-x-2">
              <button
                onClick={() => handlePageChange(currentPage - 1)}
                disabled={currentPage === 1}
                className="px-4 py-2 border border-gray-300 rounded-md text-sm font-medium text-gray-700 bg-white hover:bg-gray-50 disabled:bg-gray-100 disabled:text-gray-400 disabled:cursor-not-allowed"
              >
                Previous
              </button>

              <div className="flex items-center space-x-1">
                {Array.from({ length: totalPages }, (_, i) => i + 1).map((page) => (
                  <button
                    key={page}
                    onClick={() => handlePageChange(page)}
                    className={`w-10 h-10 flex items-center justify-center rounded-md text-sm font-medium transition-colors ${
                      currentPage === page
                        ? 'bg-indigo-600 text-white shadow-sm'
                        : 'text-gray-700 bg-white border border-gray-300 hover:bg-gray-50'
                    }`}
                  >
                    {page}
                  </button>
                ))}
              </div>

              <button
                onClick={() => handlePageChange(currentPage + 1)}
                disabled={currentPage === totalPages}
                className="px-4 py-2 border border-gray-300 rounded-md text-sm font-medium text-gray-700 bg-white hover:bg-gray-50 disabled:bg-gray-100 disabled:text-gray-400 disabled:cursor-not-allowed"
              >
                Next
              </button>
            </div>
          )}

          <div className="text-center mt-4 text-xs text-gray-400">
            Showing {Math.min(itemsPerPage, processedAds.length)} of {processedAds.length} items
          </div>
        </>
      )}
    </div>
  );
};

