import React, { useEffect } from 'react';
import { ToastMessage, ToastType } from '../types';

interface ToastContainerProps {
  toasts: ToastMessage[];
  removeToast: (id: string) => void;
}

export const ToastContainer: React.FC<ToastContainerProps> = ({ toasts, removeToast }) => {
  return (
    <div className="fixed bottom-4 right-4 z-50 flex flex-col space-y-2 pointer-events-none">
      {toasts.map((toast) => (
        <ToastItem key={toast.id} toast={toast} onRemove={() => removeToast(toast.id)} />
      ))}
    </div>
  );
};

const ToastItem: React.FC<{ toast: ToastMessage; onRemove: () => void }> = ({ toast, onRemove }) => {
  useEffect(() => {
    const timer = setTimeout(() => {
      onRemove();
    }, 4000);
    return () => clearTimeout(timer);
  }, [onRemove]);

  const bgColors: Record<ToastType, string> = {
    success: 'bg-green-600',
    error: 'bg-red-600',
    info: 'bg-indigo-600',
  };

  const icons = {
    success: (
      <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" /></svg>
    ),
    error: (
      <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
    ),
    info: (
      <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
    ),
  };

  return (
    <div className={`pointer-events-auto flex items-center w-80 max-w-sm overflow-hidden rounded-lg shadow-lg text-white transform transition-all duration-300 animate-slide-in ${bgColors[toast.type]}`}>
      <div className="p-3">
        {icons[toast.type]}
      </div>
      <div className="p-3 pl-0 flex-1">
        <p className="text-sm font-medium">{toast.message}</p>
      </div>
      <button onClick={onRemove} className="p-3 hover:bg-white/10 transition-colors">
        <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
      </button>
      <style>{`
        @keyframes slide-in {
          from { opacity: 0; transform: translateX(100%); }
          to { opacity: 1; transform: translateX(0); }
        }
        .animate-slide-in {
          animation: slide-in 0.3s ease-out forwards;
        }
      `}</style>
    </div>
  );
};

import React, { useEffect, useState, useRef } from 'react';
import { Home } from './pages/Home';
import { CreateAd } from './pages/CreateAd';
import { AdDetails } from './pages/AdDetails';
import { ManageAd } from './pages/ManageAd';
import { Admin } from './pages/Admin';
import { Modal } from './components/Modal';
import { ToastContainer } from './components/Toast';
import { Ad, AppNotification, ToastMessage, ToastType } from './types';
import { fetchNotifications, markNotificationRead, clearAllNotifications, simulateIncomingAd } from './services/mockBackend';

const App: React.FC = () => {
  const [currentPath, setCurrentPath] = useState(window.location.hash || '#/');

  // Global States
  const [isCreateModalOpen, setIsCreateModalOpen] = useState(false);
  const [selectedAd, setSelectedAd] = useState<Ad | null>(null);

  // Toast State
  const [toasts, setToasts] = useState<ToastMessage[]>([]);

  // Favorites State
  const [favorites, setFavorites] = useState<string[]>([]);

  // Notifications State
  const [notifications, setNotifications] = useState<AppNotification[]>([]);
  const [showNotifDropdown, setShowNotifDropdown] = useState(false);
  const notifDropdownRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    // Load favorites from local storage on mount
    const saved = localStorage.getItem('miculproducator_favorites');
    if (saved) {
      setFavorites(JSON.parse(saved));
    }

    // Load initial notifications
    loadNotifications();

    // Listen for notification updates
    const handleNotifUpdate = () => loadNotifications();
    window.addEventListener('miculproducator:notifications_updated', handleNotifUpdate);

    // Setup click outside for dropdown
    const handleClickOutside = (event: MouseEvent) => {
        if (notifDropdownRef.current && !notifDropdownRef.current.contains(event.target as Node)) {
            setShowNotifDropdown(false);
        }
    };
    document.addEventListener('mousedown', handleClickOutside);

    return () => {
        window.removeEventListener('miculproducator:notifications_updated', handleNotifUpdate);
        document.removeEventListener('mousedown', handleClickOutside);
    };
  }, []);

  const loadNotifications = async () => {
      const data = await fetchNotifications();
      setNotifications(data);
  };

  const addToast = (type: ToastType, message: string) => {
    const id = Math.random().toString(36).substr(2, 9);
    setToasts((prev) => [...prev, { id, type, message }]);
  };

  const removeToast = (id: string) => {
    setToasts((prev) => prev.filter((t) => t.id !== id));
  };

  const handleToggleFavorite = (id: string) => {
    let newFavs: string[];
    if (favorites.includes(id)) {
      newFavs = favorites.filter(fav => fav !== id);
      addToast('info', 'Removed from favorites');
    } else {
      newFavs = [...favorites, id];
      addToast('success', 'Added to favorites');
    }
    setFavorites(newFavs);
    localStorage.setItem('miculproducator_favorites', JSON.stringify(newFavs));
  };

  const handleNotifClick = async (notif: AppNotification) => {
      await markNotificationRead(notif.id);
      loadNotifications();
      if (notif.adId) {
          navigate(`/ad/${notif.adId}`);
          setShowNotifDropdown(false);
      }
  };

  const handleClearNotifs = async () => {
      await clearAllNotifications();
      loadNotifications();
  };

  const handleSimulateAd = () => {
      simulateIncomingAd();
      addToast('info', 'Simulating: A new ad was just posted by another user...');
  };

  useEffect(() => {
    const handleHashChange = () => {
      setCurrentPath(window.location.hash || '#/');
    };

    window.addEventListener('hashchange', handleHashChange);
    return () => window.removeEventListener('hashchange', handleHashChange);
  }, []);

  const navigate = (path: string) => {
    window.location.hash = path;
  };

  const handleOpenAdDetails = (ad: Ad) => {
    setSelectedAd(ad);
  };

  const handleCloseAdDetails = () => {
    setSelectedAd(null);
  };

  // Route matching logic
  const renderRoute = () => {
    const path = currentPath.replace('#', '');
    const searchParams = new URLSearchParams(path.split('?')[1]);
    const cleanPath = path.split('?')[0];

    if (cleanPath === '/' || cleanPath === '') {
      return (
        <Home 
          onNavigate={navigate} 
          onOpenCreateModal={() => setIsCreateModalOpen(true)}
          onAdClick={handleOpenAdDetails}
          favoriteIds={favorites}
          onToggleFavorite={handleToggleFavorite}
          onAddToast={addToast}
        />
      );
    }

    if (cleanPath === '/create') {
      return <CreateAd onNavigate={navigate} />;
    }

    if (cleanPath === '/admin') {
      return <Admin onNavigate={navigate} />;
    }

    if (cleanPath.startsWith('/ad/')) {
      const id = cleanPath.split('/ad/')[1];
      return (
        <AdDetails 
          id={id} 
          onNavigate={navigate} 
          isFavorite={favorites.includes(id)}
          onToggleFavorite={() => handleToggleFavorite(id)}
          onAddToast={addToast}
        />
      );
    }

    if (cleanPath === '/manage') {
      const id = searchParams.get('id');
      const token = searchParams.get('token');
      if (id && token) {
        return <ManageAd id={id} token={token} onNavigate={navigate} />;
      }
      return <div className="p-8 text-center text-red-600">Missing management credentials. Check your link.</div>;
    }

    return <div className="p-8 text-center">404 - Page Not Found</div>;
  };

  const unreadCount = notifications.filter(n => !n.isRead).length;

  return (
    <div className="min-h-screen flex flex-col font-sans">
      {/* Skip Navigation Link for Accessibility */}
      <a href="#main-content" className="sr-only focus:not-sr-only focus:absolute focus:top-4 focus:left-4 bg-indigo-600 text-white p-3 rounded shadow-lg z-50">
        Skip to content
      </a>

      <header className="bg-white/95 backdrop-blur-md shadow-sm sticky top-0 z-30 transition-all border-b border-gray-100">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between h-16 items-center">
            <div className="flex cursor-pointer group" onClick={() => navigate('/')} role="button" tabIndex={0} onKeyDown={(e) => e.key === 'Enter' && navigate('/')}>
              <div className="flex-shrink-0 flex items-center">
                <span className="text-2xl font-black text-indigo-600 tracking-tight group-hover:scale-105 transition-transform duration-200">
                   MiculProducator
                </span>
              </div>
            </div>

            <div className="flex items-center space-x-2 sm:space-x-4">
              {/* Notification Bell */}
              <div className="relative" ref={notifDropdownRef}>
                  <button 
                    onClick={() => setShowNotifDropdown(!showNotifDropdown)}
                    className="p-2 rounded-full text-gray-500 hover:bg-gray-100 hover:text-indigo-600 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-indigo-500 relative transition-colors"
                    aria-label="Notifications"
                  >
                      <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 17h5l-1.405-1.405A2.032 2.032 0 0118 14.158V11a6.002 6.002 0 00-4-5.659V5a2 2 0 10-4 0v.341C7.67 6.165 6 8.388 6 11v3.159c0 .538-.214 1.055-.595 1.436L4 17h5m6 0v1a3 3 0 11-6 0v-1m6 0H9" /></svg>
                      {unreadCount > 0 && (
                          <span className="absolute top-1.5 right-1.5 block h-2.5 w-2.5 rounded-full bg-red-500 ring-2 ring-white animate-pulse"></span>
                      )}
                  </button>

                  {/* Dropdown */}
                  {showNotifDropdown && (
                      <div className="absolute right-0 mt-2 w-80 bg-white rounded-md shadow-lg overflow-hidden z-50 border border-gray-100 animate-fade-in origin-top-right">
                          <div className="py-2 px-4 bg-gray-50 border-b border-gray-100 flex justify-between items-center">
                              <h3 className="text-sm font-bold text-gray-700">Notifications</h3>
                              {notifications.length > 0 && (
                                  <button onClick={handleClearNotifs} className="text-xs text-indigo-600 hover:text-indigo-800">Clear All</button>
                              )}
                          </div>
                          <div className="max-h-96 overflow-y-auto">
                              {notifications.length === 0 ? (
                                  <div className="p-4 text-center text-sm text-gray-500">No new notifications.</div>
                              ) : (
                                  notifications.map(notif => (
                                      <div 
                                        key={notif.id} 
                                        onClick={() => handleNotifClick(notif)}
                                        className={`px-4 py-3 border-b border-gray-100 cursor-pointer hover:bg-gray-50 transition-colors ${!notif.isRead ? 'bg-indigo-50/50' : ''}`}
                                      >
                                          <p className="text-sm font-semibold text-gray-800">{notif.title}</p>
                                          <p className="text-xs text-gray-600 mt-1 line-clamp-2">{notif.message}</p>
                                          <p className="text-[10px] text-gray-400 mt-1 text-right">{new Date(notif.timestamp).toLocaleTimeString()}</p>
                                      </div>
                                  ))
                              )}
                          </div>
                      </div>
                  )}
              </div>

              <button
                onClick={() => setIsCreateModalOpen(true)}
                className="ml-2 px-4 py-2 border border-transparent text-sm font-semibold rounded-full shadow-md text-white bg-indigo-600 hover:bg-indigo-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-indigo-500 transition-all duration-300 transform hover:-translate-y-0.5 hidden sm:inline-flex"
              >
                + Post Ad
              </button>
              {/* Mobile compact button */}
              <button
                onClick={() => setIsCreateModalOpen(true)}
                className="ml-2 p-2 rounded-full bg-indigo-600 text-white shadow-md sm:hidden hover:bg-indigo-700"
                aria-label="Create Ad"
              >
                  <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" /></svg>
              </button>
            </div>
          </div>
        </div>
      </header>

      <main id="main-content" className="flex-grow bg-gray-50 focus:outline-none" tabIndex={-1}>
        {renderRoute()}
      </main>

      <footer className="bg-white border-t border-gray-200">
        <div className="max-w-7xl mx-auto py-8 px-4 sm:px-6 lg:px-8">
          <div className="flex flex-col md:flex-row justify-between items-center gap-4">
             <div className="mb-4 md:mb-0">
               <span className="text-xl font-bold text-gray-300">MiculProducator</span>
             </div>
             <div className="flex flex-wrap justify-center gap-4 text-sm text-gray-500">
                <button onClick={handleSimulateAd} className="text-indigo-400 hover:text-indigo-600 underline">
                    Demo: Simulate Incoming Ad
                </button>
                <span>&copy; {new Date().getFullYear()} Made with ❤️ for Romania.</span>
                <button 
                  onClick={() => navigate('/admin')} 
                  className="text-gray-300 hover:text-gray-500 transition-colors focus:outline-none focus:underline"
                >
                  Admin Panel
                </button>
             </div>
          </div>
        </div>
      </footer>

      <Modal 
        isOpen={isCreateModalOpen} 
        onClose={() => setIsCreateModalOpen(false)}
        title="Create New Listing"
      >
        <CreateAd 
          onNavigate={navigate} 
          onClose={() => setIsCreateModalOpen(false)}
        />
      </Modal>

      <Modal
        isOpen={!!selectedAd}
        onClose={handleCloseAdDetails}
        title="Listing Details"
      >
        {selectedAd && (
          <AdDetails 
            id={selectedAd.id}
            initialData={selectedAd} 
            onClose={handleCloseAdDetails}
            isFavorite={favorites.includes(selectedAd.id)}
            onToggleFavorite={() => handleToggleFavorite(selectedAd.id)}
            onAddToast={addToast}
          />
        )}
      </Modal>

      <ToastContainer toasts={toasts} removeToast={removeToast} />
    </div>
  );
};

