// Advanced Image Processing
const processAndResizeImage = (file: File, maxWidth = 800, quality = 0.6): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = (event) => {
      const img = new Image();
      img.src = event.target?.result as string;

      img.onload = () => {
        const canvas = document.createElement('canvas');
        let width = img.width;
        let height = img.height;

        if (width > maxWidth) {
          height = Math.round((height * maxWidth) / width);
          width = maxWidth;
        }

        canvas.width = width;
        canvas.height = height;

        const ctx = canvas.getContext('2d');
        if (!ctx) {
            resolve(event.target?.result as string);
            return;
        }

        ctx.drawImage(img, 0, 0, width, height);
        // Reduced quality to save localStorage space
        resolve(canvas.toDataURL('image/jpeg', quality));
      };

      img.onerror = (e) => reject(e);
    };
    reader.onerror = (e) => reject(e);
  });
};

// --- Public API Simulations ---

export const fetchActiveAds = async (): Promise<Ad[]> => {
  await delay(50);
  const ads = getAdsFromStorage();

  if (ads.length === 0) {
    const seedAds = generateSeedAds();
    saveAdsToStorage(seedAds);
    return seedAds;
  }

  // Filter Active AND Not Expired
  const now = Date.now();
  return ads.filter((ad) => {
      const isExpired = ad.expiresAt && ad.expiresAt < now;
      return ad.status === AdStatus.ACTIVE && !isExpired;
  }).sort((a, b) => b.createdAt - a.createdAt);
};

export const fetchAdById = async (id: string): Promise<Ad | null> => {
  await delay(50);
  const ads = getAdsFromStorage();
  return ads.find((ad) => ad.id === id) || null;
};

