// Data Validation Helper to prevent UI Crashes
const isValidAd = (ad: any): ad is Ad => {
  return (
    ad &&
    typeof ad === 'object' &&
    typeof ad.id === 'string' &&
    typeof ad.title === 'string' &&
    typeof ad.price === 'number' &&
    Array.isArray(ad.categories) &&
    ad.location && typeof ad.location === 'object' &&
    (typeof ad.location.county === 'string' || typeof ad.location.city === 'string') && // Relaxed check
    Array.isArray(ad.images)
  );
};

// Initialize mock DB with Safety Checks
const getAdsFromStorage = (): Ad[] => {
  try {
    const stored = localStorage.getItem(ADS_KEY);
    if (!stored) return [];

    const parsed = JSON.parse(stored);

    if (!Array.isArray(parsed)) {
      console.warn("Corrupt storage found, resetting.");
      return [];
    }

    // Filter out corrupted items that are missing required fields
    const validAds = parsed.filter(isValidAd);

    // If we filtered out more than 20% of ads, implies serious corruption, maybe warn or not.
    if (parsed.length > 0 && validAds.length === 0) {
        console.warn("Storage contained data, but none matched current schema. Resetting to empty.");
        return [];
    }

    return validAds;
  } catch (e) {
    console.error("Error reading/parsing ads from storage", e);
    return [];
  }
};

const saveAdsToStorage = (ads: Ad[]) => {
  try {
    localStorage.setItem(ADS_KEY, JSON.stringify(ads));
  } catch (e) {
    if (e instanceof DOMException && (e.name === 'QuotaExceededError' || e.name === 'NS_ERROR_DOM_QUOTA_REACHED')) {
        alert("Storage Limit Reached: Your browser cannot store more ads/images. Some old ads might need to be deleted, or use smaller images.");
        console.error("Storage quota exceeded", e);
    } else {
        console.warn("Error saving ads", e);
    }
  }
};

// --- Cleanup & Maintenance ---

export const cleanupExpiredAds = async (): Promise<number> => {
    const ads = getAdsFromStorage();
    const now = Date.now();
    const activeAds = ads.filter(ad => {
        // Keep ads that have no expiration OR expiration is in the future
        return !ad.expiresAt || ad.expiresAt > now;
    });

    if (activeAds.length < ads.length) {
        saveAdsToStorage(activeAds);
        return ads.length - activeAds.length; // Return count of deleted ads
    }
    return 0;
};

